sql:
SELECT COUNT(*) 
FROM qa_events 
WHERE severity_level > 5;

SELECT created_by, COUNT(event_id) AS event_count
FROM qa_events
GROUP BY created_by;

SELECT type_name, COUNT(*) AS event_count
FROM event_types
GROUP BY type_name;

SELECT * 
FROM qa_events
WHERE severity_level > 5;

SELECT q.event_id, q.event_name, q.description, e.type_name, e.severity_level
FROM qa_events q
JOIN event_types e ON q.type_id = e.type_id;

SELECT e.event_name, t.technician_name
FROM qa_events e
JOIN technicians t ON e.created_by = t.technician_id;

SELECT technician_name
FROM technicians
WHERE technician_id = 2;

external_knowledge:
- 'Urgent quality control events' refers to those events classified as critical (`is_critical = 1`).;
- 'Overdue, open tasks' are those whose status is 'open' and whose due date is earlier than the current date.;
- The question is seeking to understand the severity of overdue tasks linked to critical quality control events.

sql:
SELECT DISTINCT technician_id, technician_name, role
FROM technicians
WHERE department = 'chemistry';

SELECT t.technician_name, t.role
FROM technicians t
INNER JOIN event_reports e ON e.created_by = t.technician_id;

SELECT event_name 
FROM qa_events 
WHERE severity_level > (SELECT AVG(severity_level) FROM qa_events);

SELECT type_name, AVG(severity_level) AS average_severity
FROM event_types
GROUP BY type_name;

SELECT T1.technician_name, T2.event_name
FROM technicians AS T1
INNER JOIN qa_events AS T2 ON T1.technician_id = T2.created_by;

SELECT event_name 
FROM qa_events 
WHERE event_id = 0;
